void itLipstickspore_UnkMotion0_Phys(Item_GObj* gobj)
{
    Item* ip = GET_ITEM(gobj);
    f32 vel_x = ip->x40_vel.x;
    f32 decel = ip->xDD4_itemVar.lipstickspore.xDD8;

    if (vel_x == 0.0f) {
        return;
    }

    if (decel == 0.0f) {
        return;
    }

    if (vel_x > 0.0f) {
        ip->x40_vel.x = vel_x - decel;
    } else {
        ip->x40_vel.x = vel_x + decel;
    }

    {
        f32 abs_vel = ip->x40_vel.x;
        if (abs_vel < 0.0f) {
            abs_vel = -abs_vel;
        }
        if (abs_vel < ip->xDD4_itemVar.lipstickspore.xDD8) {
            ip->x40_vel.x = 0.0f;
        }
    }
}

